INSERT INTO `v1_a7d6863551a87b37bfc3f924bb238478e8803006d19e0e19927055ad98e9db47` VALUES (1, 3, 1, "スタンダードコレクションではポスターやペナントなど\n部屋に飾れる定番グッズが盛りだくさん！\nあなたの部屋をカルミナで彩ろう！", "1回メダル{0}枚！\n定番グッズであなたの部屋をカルミナで彩ろう！", "スタンダードコレクション");
INSERT INTO `v1_a7d6863551a87b37bfc3f924bb238478e8803006d19e0e19927055ad98e9db47` VALUES (2, 10, 1, "プレミアムコレクションではサイン色紙や\nブロマイドなど、★★以上のグッズが盛りだくさん！\nレアグッズをたくさんゲットしよう！", "1回メダル{0}枚！\nメンバー直筆サイン色紙など、★★以上のグッズを確定でゲット！", "プレミアムコレクション");
INSERT INTO `v1_a7d6863551a87b37bfc3f924bb238478e8803006d19e0e19927055ad98e9db47` VALUES (3, 3, 1, "フェスコレクションではカルミナサマーライブで\n大活躍するグッズが勢ぞろい！\nゲットしたグッズを片手に、いざライブ会場へ！", "1回メダル{0}枚！\nカルミナライブに参加する際のマストアイテムをゲットしよう！", "フェスコレクション");
